export class StateStore<State, Action extends { type: string; payload?: any }> {
  private state: State;
  private reducer: (state: State, action: Action) => State;
  private listeners: Array<() => void> = [];

  constructor(initialState: State, reducer: (state: State, action: Action) => State) {
    this.state = initialState;
    this.reducer = reducer;
  }

  getState(): State {
    return this.state;
  }

  dispatch(action: Action): void {
    this.state = this.reducer(this.state, action);
    this.listeners.forEach(fn => fn());
  }

  subscribe(listener: () => void): () => void {
    this.listeners.push(listener);
    return () => {
      this.listeners = this.listeners.filter(fn => fn !== listener);
    };
  }

  select<R>(selector: (state: State) => R): R {
    return selector(this.state);
  }
}
